"use client";

import { AuthProvider, useAuth } from '@/components/providers/auth-provider';
import { BottomNav } from '@/components/dashboard/bottom-nav';
import { Search, Bell, LogOut } from 'lucide-react';
import { useExpenseStore } from '@/hooks/use-expense-store';

function DashboardShell({ children }: { children: React.ReactNode }) {
  const { signOut } = useAuth();
  const { userName, userAvatar } = useExpenseStore();

  return (
    <main className="min-h-screen bg-[#090b0e] text-white px-4 pt-8 pb-32 relative overflow-hidden">
      {/* Glow Effects de Fundo */}
      <div className="absolute -top-40 -left-20 w-80 h-80 bg-accent/20 rounded-full blur-[100px] -z-10" />
      <div className="absolute top-60 -right-20 w-80 h-80 bg-purple-500/10 rounded-full blur-[100px] -z-10" />

      <div className="max-w-md mx-auto space-y-7">
        {/* Header */}
        <div className="flex justify-between items-center px-1">
          <div className="flex items-center gap-3">
            <div className="w-11 h-11 rounded-full overflow-hidden border-2 border-accent/30 shadow-md">
              <img
                src={userAvatar || 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&w=150&q=80'}
                alt="Avatar"
                className="w-full h-full object-cover"
              />
            </div>
            <div>
              <span className="text-xs text-white/40">Bem-vindo de volta,</span>
              <p className="font-bold tracking-tight text-white/90 text-base">{userName}</p>
            </div>
          </div>

          <div className="flex gap-2">
            <button className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center border border-white/5 hover:bg-white/10 transition-colors">
              <Search size={18} className="text-white/60" />
            </button>
            <button className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center border border-white/5 hover:bg-white/10 transition-colors">
              <Bell size={18} className="text-white/60" />
            </button>
            <button
              onClick={signOut}
              className="w-10 h-10 rounded-full bg-rose-500/10 flex items-center justify-center border border-rose-500/10 hover:bg-rose-500/20 transition-colors"
              title="Sair"
            >
              <LogOut size={18} className="text-rose-400" />
            </button>
          </div>
        </div>

        {/* Conte├║do da P├ígina */}
        {children}

        {/* Navega├º├úo Inferior */}
        <BottomNav />
      </div>
    </main>
  );
}

export default function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <AuthProvider>
      <DashboardShell>{children}</DashboardShell>
    </AuthProvider>
  );
}

"use client";

import { useState } from "react";
import { useAuth } from "@/components/providers/auth-provider";
import { useExpenseStore } from "@/hooks/use-expense-store";
import { getSupabaseBrowserClient } from "@/lib/supabase-browser";
import { GlassCard } from "@/components/ui/glass-card";
import { motion } from "framer-motion";
import { User, Mail, LogOut, Camera, Save, Loader2 } from "lucide-react";

export default function ProfilePage() {
  const { user, signOut } = useAuth();
  const { userName, userAvatar, setProfile } = useExpenseStore();
  const supabase = getSupabaseBrowserClient();

  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState(userName);
  const [editAvatar, setEditAvatar] = useState(userAvatar);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        setError('A imagem deve ter menos de 2MB.');
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditAvatar(reader.result as string);
        setError("");
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveProfile = async () => {
    if (!user) return;
    setLoading(true);
    setError("");
    setSuccess("");

    try {
      // 1. Atualizar no Supabase Profiles
      const { error: dbError } = await supabase
        .from('profiles')
        .upsert({
          user_id: user.id,
          name: editName,
          avatar: editAvatar,
          updated_at: new Date().toISOString(),
        });

      if (dbError) throw dbError;

      // 2. Atualizar user_metadata no Auth (para consist├¬ncia)
      const { error: authError } = await supabase.auth.updateUser({
        data: { name: editName, avatar: editAvatar }
      });

      if (authError) throw authError;

      // 3. Atualizar Zustand Store local
      setProfile(editName, editAvatar);

      setSuccess("Perfil atualizado com sucesso!");
      setIsEditing(false);
    } catch (err: unknown) {
      console.error(err);
      setError("Erro ao atualizar o perfil. Tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  const cancelEdit = () => {
    setEditName(userName);
    setEditAvatar(userAvatar);
    setIsEditing(false);
    setError("");
    setSuccess("");
  };

  const defaultAvatar = 'https://ui-avatars.com/api/?name=' + (userName || 'User') + '&background=6366f1&color=fff';

  return (
    <div className="space-y-6 pb-20">
      <motion.div
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        className="px-1 flex justify-between items-end"
      >
        <div>
          <span className="text-sm text-white/50">Sua Conta</span>
          <h1 className="text-3xl font-black mt-1 text-white">Perfil</h1>
        </div>
        {!isEditing && (
          <button 
            onClick={() => setIsEditing(true)}
            className="text-accent text-sm font-semibold hover:text-accent/80 transition-colors"
          >
            Editar
          </button>
        )}
      </motion.div>

      {error && (
        <div className="p-3 bg-rose-500/10 border border-rose-500/20 rounded-xl text-rose-400 text-sm">
          {error}
        </div>
      )}

      {success && (
        <div className="p-3 bg-emerald-500/10 border border-emerald-500/20 rounded-xl text-emerald-400 text-sm">
          {success}
        </div>
      )}

      {/* Card de Perfil */}
      <GlassCard className="p-6 bg-gradient-to-br from-accent/5 to-transparent border-accent/10">
        <div className="flex items-center gap-4">
          <div className="relative">
            <div className="w-20 h-20 rounded-full overflow-hidden border-2 border-accent/30 shadow-lg bg-white/5">
              <img
                src={(isEditing ? editAvatar : userAvatar) || defaultAvatar}
                alt="Avatar"
                className="w-full h-full object-cover"
              />
            </div>

            {isEditing && (
              <label 
                htmlFor="avatar-upload"
                className="absolute bottom-0 right-0 w-7 h-7 bg-accent rounded-full flex items-center justify-center cursor-pointer shadow-lg hover:bg-accent/90 transition-transform active:scale-95"
              >
                <Camera size={14} className="text-white" />
                <input
                  type="file"
                  id="avatar-upload"
                  accept="image/*"
                  className="hidden"
                  onChange={handleFileChange}
                />
              </label>
            )}
          </div>

          <div className="flex-1">
            {isEditing ? (
              <div className="space-y-2">
                <input
                  type="text"
                  value={editName}
                  onChange={(e) => setEditName(e.target.value)}
                  placeholder="Seu nome completo"
                  className="w-full bg-white/10 border border-white/20 rounded-lg py-2 px-3 text-sm text-white focus:outline-none focus:border-accent/50"
                />
              </div>
            ) : (
              <>
                <h2 className="text-xl font-bold text-white">{userName || 'Usu├írio'}</h2>
                <div className="flex items-center gap-1.5 mt-1">
                  <Mail size={12} className="text-white/40" />
                  <p className="text-xs text-white/40 truncate">{user?.email || 'email@n├úo.encontrado'}</p>
                </div>
              </>
            )}
          </div>
        </div>

        {isEditing && (
          <div className="flex gap-3 mt-6">
            <button
              onClick={cancelEdit}
              className="flex-1 py-2.5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl text-sm font-semibold text-white/80 transition-colors"
            >
              Cancelar
            </button>
            <button
              onClick={handleSaveProfile}
              disabled={loading || !editName.trim()}
              className="flex-1 py-2.5 bg-accent hover:bg-accent/90 disabled:opacity-50 disabled:cursor-not-allowed rounded-xl text-sm font-bold flex items-center justify-center gap-2 text-white transition-colors"
            >
              {loading ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
              Salvar
            </button>
          </div>
        )}
      </GlassCard>

      {/* Informa├º├Áes da Conta */}
      <GlassCard className="p-5 space-y-4">
        <div className="flex items-center gap-3">
          <div className="p-2.5 rounded-xl bg-white/5 border border-white/5">
            <User size={18} className="text-white/60" />
          </div>
          <div>
            <p className="text-xs text-white/40">Membro desde</p>
            <p className="text-sm font-bold text-white">
              {user?.created_at
                ? new Intl.DateTimeFormat('pt-BR', {
                    day: '2-digit',
                    month: 'long',
                    year: 'numeric',
                  }).format(new Date(user.created_at))
                : 'ÔÇö'}
            </p>
          </div>
        </div>
      </GlassCard>

      {/* Bot├úo de Logout */}
      <motion.button
        whileTap={{ scale: 0.95 }}
        onClick={signOut}
        className="w-full py-3.5 bg-rose-500/10 border border-rose-500/20 rounded-2xl text-rose-400 font-bold text-sm flex items-center justify-center gap-2 hover:bg-rose-500/20 transition-colors"
      >
        <LogOut size={18} />
        Sair da Conta
      </motion.button>
    </div>
  );
}

"use client";

import { useState } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { motion } from 'framer-motion';
import { getSupabaseBrowserClient } from '@/lib/supabase-browser';
import { Mail, Lock, User, ArrowRight, Camera, Eye, EyeOff } from 'lucide-react';
import { GlassCard } from '@/components/ui/glass-card';

// Mensagens de erro traduzidas
const ERROR_MESSAGES: Record<string, string> = {
  'Invalid login credentials': 'E-mail ou senha incorretos.',
  'Email not confirmed': 'Confirme seu e-mail antes de fazer login.',
  'User already registered': 'Este e-mail j├í est├í cadastrado.',
  'Password should be at least 6 characters': 'A senha deve ter no m├¡nimo 6 caracteres.',
  'Signup requires a valid password': 'Informe uma senha v├ílida.',
  'Unable to validate email address: invalid format': 'Formato de e-mail inv├ílido.',
  'Email rate limit exceeded': 'Muitas tentativas. Aguarde alguns minutos.',
  'Email signups are disabled': 'Cadastro por e-mail est├í desativado. Ative no painel do Supabase.',
  'Signups not allowed for this instance': 'Cadastro n├úo permitido nesta inst├óncia.',
  'auth_callback_failed': 'Erro na confirma├º├úo do e-mail. Tente novamente.',
};

function translateError(message: string): string {
  return ERROR_MESSAGES[message] || `Erro: ${message}`;
}

export const LoginView = () => {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(searchParams.get('error') ? translateError(searchParams.get('error')!) : '');
  const [success, setSuccess] = useState('');
  const [showPassword, setShowPassword] = useState(false);

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [avatar, setAvatar] = useState('');

  const supabase = getSupabaseBrowserClient();

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        setError('A imagem deve ter menos de 2MB.');
        return;
      }
      const reader = new FileReader();
      reader.onloadend = () => {
        setAvatar(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess('');

    try {
      if (isLogin) {
        const { error } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
        router.push('/');
      } else {
        const { error } = await supabase.auth.signUp({
          email,
          password,
          options: {
            emailRedirectTo: `${window.location.origin}/auth/callback`,
            data: {
              name: name || email.split('@')[0],
              avatar: avatar || 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&w=150&q=80',
            }
          }
        });
        if (error) throw error;
        setSuccess('Conta criada! Verifique seu e-mail para confirmar.');
      }
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Ocorreu um erro inesperado.';
      setError(translateError(message));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-[#090b0e] px-4">
      {/* Background Glows */}
      <div className="absolute top-1/4 left-1/4 w-80 h-80 bg-accent/30 rounded-full blur-[120px] -z-10" />
      <div className="absolute bottom-1/4 right-1/4 w-80 h-80 bg-purple-500/20 rounded-full blur-[120px] -z-10" />

      <motion.div
        initial={{ opacity: 0, y: 20, scale: 0.95 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        transition={{ duration: 0.4 }}
        className="w-full max-w-md"
      >
        <GlassCard className="p-8 border-white/10 shadow-2xl">
          <div className="text-center mb-8">
            <h1 className="text-3xl font-black tracking-tight text-white mb-2">
              {isLogin ? 'Bem-vindo de volta' : 'Criar Conta'}
            </h1>
            <p className="text-sm text-white/50">
              {isLogin
                ? 'Acesse seus gastos e controle suas finan├ºas.'
                : 'Comece a organizar seu dinheiro de forma inteligente.'}
            </p>
          </div>

          {error && (
            <div className="mb-4 p-3 bg-rose-500/10 border border-rose-500/20 rounded-xl text-rose-400 text-xs text-center">
              {error}
            </div>
          )}

          {success && (
            <div className="mb-4 p-3 bg-emerald-500/10 border border-emerald-500/20 rounded-xl text-emerald-400 text-xs text-center">
              {success}
            </div>
          )}

          <form onSubmit={handleAuth} className="space-y-4">
            {!isLogin && (
              <div className="space-y-1">
                <label className="text-xs text-white/60 ml-1">Nome</label>
                <div className="relative">
                  <User size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" />
                  <input
                    type="text"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="Seu nome"
                    className="w-full bg-white/5 border border-white/10 rounded-xl py-2.5 pl-10 pr-4 text-sm text-white focus:outline-none focus:border-accent/40 transition-colors"
                    required={!isLogin}
                  />
                </div>
              </div>
            )}

            <div className="space-y-1">
              <label className="text-xs text-white/60 ml-1">E-mail</label>
              <div className="relative">
                <Mail size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" />
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="seu@email.com"
                  className="w-full bg-white/5 border border-white/10 rounded-xl py-2.5 pl-10 pr-4 text-sm text-white focus:outline-none focus:border-accent/40 transition-colors"
                  required
                />
              </div>
            </div>

            <div className="space-y-1">
              <label className="text-xs text-white/60 ml-1">Senha</label>
              <div className="relative">
                <Lock size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-white/40" />
                <input
                  type={showPassword ? "text" : "password"}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                  className="w-full bg-white/5 border border-white/10 rounded-xl py-2.5 pl-10 pr-10 text-sm text-white focus:outline-none focus:border-accent/40 transition-colors"
                  required
                  minLength={6}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-white/40 hover:text-white/60"
                >
                  {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            {!isLogin && (
              <div className="space-y-1">
                <label className="text-xs text-white/60 ml-1">Foto de Perfil</label>
                <div className="relative">
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handleFileChange}
                    className="hidden"
                    id="avatar-upload"
                  />
                  <label
                    htmlFor="avatar-upload"
                    className="w-full bg-white/5 border border-white/10 border-dashed rounded-xl py-3 px-4 flex items-center justify-center gap-2 cursor-pointer hover:bg-white/10 transition-colors"
                  >
                    {avatar ? (
                      <div className="flex items-center gap-2">
                        <img src={avatar} alt="Preview" className="w-6 h-6 rounded-full object-cover" />
                        <span className="text-xs text-white/80">Foto selecionada</span>
                      </div>
                    ) : (
                      <>
                        <Camera size={16} className="text-white/40" />
                        <span className="text-xs text-white/60">Escolher foto do dispositivo</span>
                      </>
                    )}
                  </label>
                </div>
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-accent hover:bg-accent/90 text-black font-bold h-11 rounded-xl flex items-center justify-center gap-2 mt-6 transition-all active:scale-95 disabled:opacity-50"
            >
              {loading ? 'Carregando...' : isLogin ? 'Entrar' : 'Criar Conta'}
              {!loading && <ArrowRight size={18} />}
            </button>
          </form>

          <div className="mt-6 text-center">
            <button
              onClick={() => {
                setIsLogin(!isLogin);
                setError('');
                setSuccess('');
              }}
              className="text-xs text-accent hover:underline"
            >
              {isLogin ? 'N├úo tem conta? Cadastre-se' : 'J├í tem conta? Fa├ºa Login'}
            </button>
          </div>

          <div className="mt-8 pt-4 border-t border-white/5 text-center">
            <button
              onClick={async () => {
                setLoading(true);
                try {
                  await fetch('/api/auth/clear-session', { method: 'POST' });
                  document.cookie.split(";").forEach((c) => {
                    document.cookie = c.replace(/^ +/, "").replace(/=.*/, "=;expires=" + new Date().toUTCString() + ";path=/");
                  });
                  window.location.reload();
                } catch (e) {
                  console.error(e);
                  setLoading(false);
                }
              }}
              className="text-[10px] text-white/30 hover:text-white/60 transition-colors uppercase tracking-wider"
            >
              Erro ao entrar? Clique aqui para limpar dados
            </button>
          </div>

        </GlassCard>
      </motion.div>
    </div>
  );
};

